“multi_tool_use.parallel”：{
    "description": "此工具充当使用多个工具的包装器。必须在开发人员消息的工具部分中指定可以使用的每个工具。仅允许使用函数命名空间中的工具。\n确保提供给每个工具的参数根据该工具的规范有效。\n使用此函数可以同时运行多个工具，但前提是它们可以并行操作。",
    “类型”：“对象”，
    “属性”：{
      “工具用途”：{
        "description": "要并行执行的工具。注意：只允许使用功能工具",
        “类型”：“数组”，
        “项目”：{
          “类型”：“对象”，
          “属性”：{
            “收件人姓名”：{
              “类型”：“字符串”，
              "description": "要使用的工具的名称。格式必须为函数。<function_name>。"
            },
            “参数”：{
              “类型”：“对象”，
              "description": "传递给工具的参数。根据工具自身的规范，确保这些参数有效。"
            }
          },
          “必需”：[“收件人名称”，“参数”]
        }
      }
